import { useRef, useEffect, useCallback } from 'react'
import { useVoice } from '../../contexts/VoiceContext.js'
import { stripAnsi } from './utils.js'
import {
  TTS_TAG_REGEX,
  CODE_PATTERN_REGEX,
  MAX_TTS_BUFFER_SIZE,
  MAX_SPOKEN_SET_SIZE,
  MIN_SILENT_PERIOD_MS,
} from './constants.js'

interface UseTTSOptions {
  ptyId: string
  isActive: boolean
}

interface UseTTSReturn {
  processTTSChunk: (cleanChunk: string) => void
  handleUserInput: (data: string) => void
  resetTTSState: () => void
  prePopulateSpokenContent: (chunks: string[]) => void
}

/**
 * Hook for handling Text-to-Speech functionality in the terminal.
 * Extracts TTS tags from terminal output and speaks content when appropriate.
 */
export function useTTS({ ptyId, isActive }: UseTTSOptions): UseTTSReturn {
  const { voiceOutputEnabled, speakText } = useVoice()

  // Refs for TTS state
  const voiceOutputEnabledRef = useRef(voiceOutputEnabled)
  const isActiveRef = useRef(isActive)
  const spokenContentRef = useRef<Set<string>>(new Set())
  const silentModeRef = useRef(true)
  const sessionStartTimeRef = useRef(Date.now())
  const ttsBufferRef = useRef('')

  // Keep refs in sync with props
  useEffect(() => {
    voiceOutputEnabledRef.current = voiceOutputEnabled
  }, [voiceOutputEnabled])

  useEffect(() => {
    isActiveRef.current = isActive
  }, [isActive])

  // Reset TTS state for new session
  const resetTTSState = useCallback(() => {
    silentModeRef.current = true
    spokenContentRef.current.clear()
    ttsBufferRef.current = ''
    sessionStartTimeRef.current = Date.now()
  }, [])

  // Pre-populate spoken content from buffered data (for HMR recovery)
  const prePopulateSpokenContent = useCallback((chunks: string[]) => {
    for (const chunk of chunks) {
      const cleanChunk = stripAnsi(chunk)
      const tagRegex = /(?:«tts»|<tts>)([\s\S]*?)(?:«\/tts»|<\/tts>)/g
      let match
      while ((match = tagRegex.exec(cleanChunk)) !== null) {
        const content = match[1].trim()
        if (content.length > 3) {
          spokenContentRef.current.add(content)
        }
      }
    }
  }, [])

  // Handle user input to exit silent mode
  const handleUserInput = useCallback((data: string) => {
    // Ignore terminal control sequences
    if (data.startsWith('\x1b[') && (data.endsWith('R') || data === '\x1b[I' || data === '\x1b[O')) {
      return
    }

    // Ignore Enter and arrow keys - these navigate TOS dialogs
    const isEnterKey = data === '\r' || data === '\n'
    const isArrowKey = data === '\x1b[A' || data === '\x1b[B' || data === '\x1b[C' || data === '\x1b[D'
    const timeSinceStart = Date.now() - sessionStartTimeRef.current

    if (silentModeRef.current && !isEnterKey && !isArrowKey && timeSinceStart >= MIN_SILENT_PERIOD_MS) {
      silentModeRef.current = false
      // Clear TTS buffer to discard partial tags from session restoration
      ttsBufferRef.current = ''
    }
  }, [])

  // Process a chunk of terminal data for TTS
  const processTTSChunk = useCallback((cleanChunk: string) => {
    ttsBufferRef.current += cleanChunk

    // Extract all complete TTS markers from buffer
    TTS_TAG_REGEX.lastIndex = 0
    let match
    let lastIndex = 0

    while ((match = TTS_TAG_REGEX.exec(ttsBufferRef.current)) !== null) {
      lastIndex = match.index + match[0].length
      const content = match[1].trim()

      // Skip if content looks like code
      const looksLikeCode = CODE_PATTERN_REGEX.test(content)
      const looksLikeProse = content.length > 5 && /^[a-zA-Z]/.test(content) && !looksLikeCode

      if (looksLikeProse && !spokenContentRef.current.has(content)) {
        spokenContentRef.current.add(content)
        // Only speak if: voice enabled, tab active, and not in silent mode
        if (voiceOutputEnabledRef.current && isActiveRef.current && !silentModeRef.current) {
          speakText(content)
        }
      }
    }

    // Keep only the part after the last complete tag
    if (lastIndex > 0) {
      ttsBufferRef.current = ttsBufferRef.current.substring(lastIndex)
    }

    // If buffer has no opening marker, clear it — there's nothing to wait for
    if (!ttsBufferRef.current.includes('«tts') && !ttsBufferRef.current.includes('<tts')) {
      ttsBufferRef.current = ''
    }

    // Limit buffer size
    if (ttsBufferRef.current.length > MAX_TTS_BUFFER_SIZE) {
      ttsBufferRef.current = ttsBufferRef.current.substring(ttsBufferRef.current.length - MAX_TTS_BUFFER_SIZE)
    }

    // Limit spoken set size
    if (spokenContentRef.current.size > MAX_SPOKEN_SET_SIZE) {
      const entries = Array.from(spokenContentRef.current)
      spokenContentRef.current = new Set(entries.slice(-500))
    }
  }, [speakText])

  return {
    processTTSChunk,
    handleUserInput,
    resetTTSState,
    prePopulateSpokenContent,
  }
}

// Piper TTS - speech synthesis with Piper

import { app } from 'electron'
import * as fs from 'fs'
import * as path from 'path'
import { spawn, ChildProcess } from 'child_process'

import { isWindows } from '../platform.js'
import { piperDir, piperVoicesDir, PIPER_BINARY_URLS } from './paths.js'
import { downloadFile, extractArchive, ensureDir } from './download.js'
import { logTTS } from './debug.js'
import { getAnyVoicePath, getInstalledPiperVoices, getInstalledVoices } from './voice-discovery.js'
import { PIPER_VOICES, type PiperVoiceName, type ProgressCallback, type TTSStatus } from './types.js'

let speakingProcess: ChildProcess | null = null
let speakQueue: Promise<{ success: boolean; audioData?: string; error?: string }> = Promise.resolve({ success: true })

export function getPiperBinaryPath(): string | null {
  const binaryName = isWindows ? 'piper.exe' : 'piper'
  // Piper extracts to a 'piper' subdirectory
  const binaryPath = path.join(piperDir, 'piper', binaryName)
  if (fs.existsSync(binaryPath)) return binaryPath
  // Also check direct path
  const directPath = path.join(piperDir, binaryName)
  if (fs.existsSync(directPath)) return directPath
  // Also check system PATH (e.g., /usr/bin/piper from package manager)
  if (!isWindows) {
    const systemPaths = ['/usr/bin/piper', '/usr/local/bin/piper']
    for (const sysPath of systemPaths) {
      if (fs.existsSync(sysPath)) return sysPath
    }
  }
  return null
}

export function isPiperInstalled(): boolean {
  return getPiperBinaryPath() !== null
}

export async function checkTTS(currentVoice: string): Promise<TTSStatus> {
  const piperInstalled = isPiperInstalled()
  const voices = getInstalledPiperVoices()

  return {
    installed: piperInstalled && voices.length > 0,
    engine: piperInstalled ? 'piper' : null,
    voices,
    currentVoice: voices.includes(currentVoice) ? currentVoice : voices[0] || null
  }
}

export async function installPiper(
  onProgress?: ProgressCallback
): Promise<{ success: boolean; error?: string }> {
  try {
    ensureDir(piperDir)

    const platform = process.platform as 'win32' | 'darwin' | 'linux'
    const url = PIPER_BINARY_URLS[platform]
    if (!url) {
      return { success: false, error: `Unsupported platform: ${platform}` }
    }

    const ext = isWindows ? '.zip' : '.tar.gz'
    const archivePath = path.join(piperDir, `piper${ext}`)

    onProgress?.('Downloading Piper TTS...', 0)
    await downloadFile(url, archivePath, (percent) => {
      onProgress?.('Downloading Piper TTS...', percent)
    })

    onProgress?.('Extracting Piper TTS...', undefined)
    await extractArchive(archivePath, piperDir)

    // Cleanup archive
    fs.unlinkSync(archivePath)

    // Make binary executable on Unix
    if (!isWindows) {
      const binaryPath = getPiperBinaryPath()
      if (binaryPath) {
        fs.chmodSync(binaryPath, 0o755)
      }
    }

    if (!isPiperInstalled()) {
      return { success: false, error: 'Piper extraction failed' }
    }

    onProgress?.('Piper TTS installed successfully', 100)
    return { success: true }
  } catch (e: any) {
    return { success: false, error: e.message }
  }
}

export async function downloadPiperVoice(
  voice: PiperVoiceName,
  onProgress?: ProgressCallback
): Promise<{ success: boolean; error?: string }> {
  try {
    ensureDir(piperVoicesDir)

    const voiceInfo = PIPER_VOICES[voice]
    const modelPath = path.join(piperVoicesDir, voiceInfo.file)
    const configPath = path.join(piperVoicesDir, voiceInfo.config)

    onProgress?.(`Downloading voice: ${voiceInfo.description}...`, 0)

    // Download model file
    await downloadFile(voiceInfo.url, modelPath, (percent) => {
      onProgress?.('Downloading voice model...', Math.round(percent * 0.9))
    })

    // Download config file
    await downloadFile(voiceInfo.configUrl, configPath, () => {
      onProgress?.('Downloading voice config...', 95)
    })

    onProgress?.('Voice installed successfully', 100)
    return { success: true }
  } catch (e: any) {
    return { success: false, error: e.message }
  }
}

export function speak(
  text: string,
  currentVoice: string,
  ttsSpeed: number
): Promise<{ success: boolean; audioData?: string; error?: string }> {
  // Serialize speak calls to prevent concurrent Piper processes from
  // clobbering the global speakingProcess reference
  const result = speakQueue.then(() => speakInternal(text, currentVoice, ttsSpeed),
    () => speakInternal(text, currentVoice, ttsSpeed))
  speakQueue = result
  return result
}

async function speakInternal(
  text: string,
  currentVoice: string,
  ttsSpeed: number
): Promise<{ success: boolean; audioData?: string; error?: string }> {
  logTTS('piper speak() called', {
    textLength: text.length,
    text: text.substring(0, 200) + (text.length > 200 ? '...' : ''),
    voice: currentVoice,
    speed: ttsSpeed
  })

  const piperPath = getPiperBinaryPath()
  if (!piperPath) {
    logTTS('ERROR: Piper not installed')
    return { success: false, error: 'Piper not installed' }
  }

  // Use getAnyVoicePath to support built-in, downloaded, and custom voices
  let voicePaths = getAnyVoicePath(currentVoice)
  let voiceToUse = currentVoice

  if (!voicePaths) {
    // Current voice not found - try to fall back to any available voice
    const availableVoices = getInstalledVoices()
    for (const voice of availableVoices) {
      voicePaths = getAnyVoicePath(voice.key)
      if (voicePaths) {
        voiceToUse = voice.key
        break
      }
    }
    if (!voicePaths) {
      return { success: false, error: 'No voices installed' }
    }
  }

  try {
    const tempDir = app.getPath('temp')
    const outputPath = path.join(tempDir, `tts_${Date.now()}.wav`)

    // Piper takes text from stdin and outputs WAV to file
    // length_scale: <1 = faster, >1 = slower. Convert from our speed (>1 = faster)
    const lengthScale = 1.0 / ttsSpeed
    const args = [
      '--model', voicePaths.model,
      '--output_file', outputPath,
      '--length_scale', lengthScale.toFixed(2)
    ]

    logTTS('Spawning Piper', {
      piperPath,
      args,
      lengthScale,
      model: voicePaths.model,
      outputPath
    })

    return new Promise((resolve) => {
      const proc = spawn(piperPath, args)
      speakingProcess = proc

      let stderrOutput = ''
      proc.stderr?.on('data', (data) => {
        stderrOutput += data.toString()
      })

      logTTS('Writing text to Piper stdin', { textBytes: Buffer.byteLength(text, 'utf8') })
      proc.stdin.write(text)
      proc.stdin.end()

      proc.on('close', (code) => {
        speakingProcess = null
        logTTS('Piper process closed', { code, stderrOutput: stderrOutput.substring(0, 500) })

        if (code === 0 && fs.existsSync(outputPath)) {
          // Read file and return as base64
          const audioBuffer = fs.readFileSync(outputPath)
          const audioData = audioBuffer.toString('base64')
          logTTS('Audio generated successfully', {
            audioSize: audioBuffer.length,
            base64Length: audioData.length
          })
          // Clean up temp file
          fs.unlinkSync(outputPath)
          resolve({ success: true, audioData })
        } else {
          logTTS('ERROR: Piper failed', { code, stderrOutput })
          resolve({ success: false, error: `Piper exited with code ${code}` })
        }
      })

      proc.on('error', (err) => {
        speakingProcess = null
        logTTS('ERROR: Piper spawn error', { error: err.message })
        resolve({ success: false, error: err.message })
      })
    })
  } catch (e: any) {
    return { success: false, error: e.message }
  }
}

export function stopSpeaking(): void {
  if (speakingProcess) {
    speakingProcess.kill()
    speakingProcess = null
  }
}

import * as fs from 'fs'
import { spawn, ChildProcess } from 'child_process'
import {
  xttsDir,
  xttsScriptPath,
  getVenvPython,
  ensureDir,
  XTTS_HELPER_SCRIPT
} from './xtts-paths.js'
import { isWindows } from './platform.js'

type RequestHandler = {
  resolve: (result: unknown) => void
  reject: (err: Error) => void
}

export class XTTSServer {
  private serverProcess: ChildProcess | null = null
  private serverReady = false
  private serverStarting: Promise<boolean> | null = null
  private pendingRequests: Map<string, RequestHandler> = new Map()
  private responseBuffer = ''
  private pythonPath: string | null = null

  constructor(pythonPath: string | null) {
    this.pythonPath = pythonPath
  }

  setPythonPath(pythonPath: string | null): void {
    this.pythonPath = pythonPath
  }

  isRunning(): boolean {
    return this.serverProcess !== null && this.serverReady
  }

  async start(): Promise<boolean> {
    if (this.serverStarting) {
      return this.serverStarting
    }

    if (this.serverProcess && this.serverReady) {
      return true
    }

    this.serverStarting = this.startInternal()
    const result = await this.serverStarting
    this.serverStarting = null
    return result
  }

  private async startInternal(): Promise<boolean> {
    const venvPython = getVenvPython()
    const pythonToUse = fs.existsSync(venvPython) ? venvPython : this.pythonPath

    if (!pythonToUse) {
      return false
    }

    this.ensureHelperScript()

    return new Promise((resolve) => {
      const proc = spawn(pythonToUse, [xttsScriptPath, 'server'])
      this.serverProcess = proc
      this.serverReady = false
      this.responseBuffer = ''

      proc.stdout.on('data', (data) => {
        this.responseBuffer += data.toString()

        const lines = this.responseBuffer.split('\n')
        this.responseBuffer = lines.pop() || ''

        for (const line of lines) {
          if (!line.trim()) continue

          try {
            const response = JSON.parse(line)

            if (response.status === 'ready') {
              this.serverReady = true
              resolve(true)
              continue
            }

            const entry = this.pendingRequests.entries().next().value
            if (entry) {
              const [requestId, handlers] = entry
              this.pendingRequests.delete(requestId)
              handlers.resolve(response)
            }
          } catch (e) {
            console.error('XTTS server parse error:', e, 'line:', line)
          }
        }
      })

      proc.stderr.on('data', (data) => {
        console.log('XTTS server:', data.toString())
      })

      proc.on('close', (code) => {
        this.serverProcess = null
        this.serverReady = false

        for (const [, handlers] of this.pendingRequests) {
          handlers.reject(new Error(`Server exited with code ${code}`))
        }
        this.pendingRequests.clear()
        for (const queued of this.requestQueue) {
          queued.reject(new Error(`Server exited with code ${code}`))
        }
        this.requestQueue = []
        this.processingRequest = false

        if (!this.serverReady) {
          resolve(false)
        }
      })

      proc.on('error', () => {
        this.serverProcess = null
        this.serverReady = false
        resolve(false)
      })

      setTimeout(() => {
        if (!this.serverReady) {
          console.error('XTTS server startup timeout')
          this.stop()
          resolve(false)
        }
      }, 120000)
    })
  }

  stop(): void {
    if (this.serverProcess) {
      try {
        this.serverProcess.stdin?.write(JSON.stringify({ action: 'quit' }) + '\n')
      } catch {
        // Ignore write errors
      }

      setTimeout(() => {
        if (this.serverProcess) {
          this.serverProcess.kill()
          this.serverProcess = null
        }
      }, 1000)
    }
    this.serverReady = false
  }

  private requestQueue: Array<{ command: object; resolve: (v: unknown) => void; reject: (e: Error) => void }> = []
  private processingRequest = false

  async sendCommand(command: object): Promise<unknown> {
    if (!this.serverProcess || !this.serverReady) {
      const started = await this.start()
      if (!started) {
        throw new Error('Failed to start XTTS server')
      }
    }

    // Serialize requests: XTTS Python server processes one at a time and
    // responses have no request ID, so we must send sequentially to match
    // responses to the correct caller.
    return new Promise((resolve, reject) => {
      this.requestQueue.push({ command, resolve, reject })
      this.processNextRequest()
    })
  }

  private processNextRequest(): void {
    if (this.processingRequest || this.requestQueue.length === 0) return
    this.processingRequest = true

    const { command, resolve, reject } = this.requestQueue.shift()!
    const requestId = `${Date.now()}-${Math.random()}`
    this.pendingRequests.set(requestId, {
      resolve: (result) => {
        this.processingRequest = false
        resolve(result)
        this.processNextRequest()
      },
      reject: (err) => {
        this.processingRequest = false
        reject(err)
        this.processNextRequest()
      }
    })

    try {
      this.serverProcess!.stdin?.write(JSON.stringify(command) + '\n')
    } catch (err) {
      this.pendingRequests.delete(requestId)
      this.processingRequest = false
      reject(err as Error)
      this.processNextRequest()
    }

    setTimeout(() => {
      if (this.pendingRequests.has(requestId)) {
        this.pendingRequests.delete(requestId)
        this.processingRequest = false
        reject(new Error('Request timeout'))
        this.processNextRequest()
      }
    }, 300000)
  }

  private ensureHelperScript(): void {
    ensureDir(xttsDir)
    fs.writeFileSync(xttsScriptPath, XTTS_HELPER_SCRIPT)
    if (!isWindows) {
      fs.chmodSync(xttsScriptPath, 0o755)
    }
  }
}

